        if (R.syncBars) { const v = parseFloat(hold.value); R.holdBars = (Number.isFinite(v) && v > 0) ? Math.min(64, v) : 0; }
        else { R.holdMs = Math.max(0, Math.min(600000, parseInt(hold.value, 10) || 0)); }
